import React, { useState } from 'react';
import {
  CHeader,
  CContainer,
  CHeaderBrand,
  CHeaderNav,
  CHeaderToggler,
} from '@coreui/react';
import { cilMenu } from '@coreui/icons';
import CIcon from '@coreui/icons-react';
import SearchBar from './SearchBar'; // create a small search input component
import ProfileDropdown from './ProfileDropdown'; // profile image + dropdown
// import NotificationIcon from './NotificationIcon'; // bell icon
import { CButton } from '@coreui/react';
import { cilBell } from '@coreui/icons';

import { CDropdown, CDropdownToggle, CDropdownMenu, CDropdownItem } from '@coreui/react';



const Header = ({ sidebarShow, setSidebarShow }) => {

  const NotificationIcon = () => {
    return (
      <CButton color="light" className="position-relative rounded-circle p-2">
        <CIcon icon={cilBell} size="lg" />
        {/* Optional: Add a badge */}
        <span
          className="position-absolute top-0 start-100 translate-middle p-1 bg-danger border border-light rounded-circle"
          style={{ fontSize: '8px' }}
        ></span>
      </CButton>
    );
  };

  const ProfileDropdown = () => {
    const [visible, setVisible] = useState(false);

    return (
      <CDropdown visible={visible} onVisibleChange={setVisible} className="profile-dropdown">
        <CDropdownToggle className="p-0 border-0 bg-transparent">
          <img
            src={"https://ui-avatars.com/api/?name=Dheeraj+Khanna"}
            alt="User"
            className="rounded-circle"
            width="36"
            height="36"
            style={{ objectFit: 'cover' }}
          />
        </CDropdownToggle>
        <CDropdownMenu className="pt-0">
          <CDropdownItem href="#">Profile</CDropdownItem>
          <CDropdownItem href="#">Settings</CDropdownItem>
          <CDropdownItem href="#">Logout</CDropdownItem>
        </CDropdownMenu>
      </CDropdown>
    );
  };



  return (
    <CHeader position="sticky" className="app-header shadow-sm px-3">
      <CContainer fluid className="d-flex align-items-center justify-content-between">
        <div className="d-flex align-items-center gap-3">
          <CHeaderToggler
            className="sidebar-toggler"
            onClick={() => setSidebarShow(!sidebarShow)}
          >
            <CIcon icon={cilMenu} size="lg" />
          </CHeaderToggler>
          <CHeaderBrand className="logo-text">
            <h5 className="mb-0">My Dashboard</h5>
          </CHeaderBrand>
        </div>

        <SearchBar />

        <div className="d-flex align-items-center gap-4">
          {/* <NotificationIcon /> */}
          {NotificationIcon()}
          {ProfileDropdown()}
          {/* <ProfileDropdown /> */}
        </div>
      </CContainer>
    </CHeader>
  );
};

export default Header;
